#include <stdio.h>
#include <stdlib.h>
#define MAXN 150

int max(int a, int b) { return a > b ? a : b; }

int main() {
    int N;
    scanf("%d", &N);
    int seq1[MAXN], seq2[MAXN];
    for (int i = 0; i < N; i++) scanf("%d", &seq1[i]);
    for (int i = 0; i < N; i++) scanf("%d", &seq2[i]);

    int diff1[MAXN - 1], diff2[MAXN - 1];
    for (int i = 0; i < N - 1; i++) {
        diff1[i] = seq1[i + 1] - seq1[i];
        diff2[i] = seq2[i + 1] - seq2[i];
    }

    int dp[MAXN][MAXN] = {0};
    int maxLen = 0, maxEnd1 = 0, maxEnd2 = 0;
    for (int i = 0; i < N - 1; i++) {
        for (int j = 0; j < N - 1; j++) {
            if (diff1[i] == diff2[j]) {
                if (i == 0 || j == 0) dp[i][j] = 1;
                else dp[i][j] = dp[i - 1][j - 1] + 1;
                if (dp[i][j] > maxLen) {
                    maxLen = dp[i][j];
                    maxEnd1 = i;
                    maxEnd2 = j;
                }
            }
        }
    }

    printf("%d\n", maxLen + 1);
    for (int i = maxEnd1; i >= maxEnd1 - maxLen + 1; i--) printf("%d ", seq1[i]);
    printf("\n");
    for (int i = maxEnd2; i >= maxEnd2 - maxLen + 1; i--) printf("%d ", seq2[i]);
    printf("\n");

    return 0;
}

