    diff1.push(seq1[i + 1] - seq1[i]);
    diff2.push(seq2[i + 1] - seq2[i]);
}

const dp = Array(N).fill(0).map(() => Array(N).fill(0));
let maxLen = 0;
let maxEnd1 = 0;
let maxEnd2 = 0;
for (let i = 0; i < N - 1; i++) {
    for (let j = 0; j < N - 1; j++) {
